const items = $input.all();

// Extract all scores
const scores = items
  .map(item => parseFloat(item.json['AI Score']))
  .filter(score => !isNaN(score));

// Calculate stats
const totalLeads = items.length;
const avgScore = (scores.reduce((a, b) => a + b, 0) / scores.length).toFixed(1);
const highestScore = Math.max(...scores);
const lowestScore = Math.min(...scores);

// Get top 3 leads
const topLeads = items
  .filter(item => !isNaN(parseFloat(item.json['AI Score'])))
  .sort((a, b) => parseFloat(b.json['AI Score']) - parseFloat(a.json['AI Score']))
  .slice(0, 3)
  .map(item => `${item.json['Company Name']} (Score: ${item.json['AI Score']})`)
  .join(', ');

return [{
  json: {
    totalLeads,
    avgScore,
    highestScore,
    lowestScore,
    topLeads,
    reportDate: new Date().toDateString(),
  }
}];

const item = $input.first();
const text = item.json.output?.[0]?.content?.[0]?.text || "";

const subjectMatch = text.match(/Subject:\s*(.+)/);
const body = text.replace(/Subject:\s*.+\n/, "").trim();

return [{
  json: {
    subject: subjectMatch ? subjectMatch[1].trim() : "Weekly Lead Generation Report",
    body: body,
  }
}];
